import { useState, useEffect } from 'react';
import './index.css';
import LoginPage from './components/LoginPage';
import PatientIntakeForm from './components/PatientIntakeForm';
import NeuDashboard from './components/NeuDashboard';
import { useSimulation } from './hooks/useSimulation';
import type { LoginState } from './simulation/types';

function App() {
  const [loginState, setLoginState] = useState<LoginState>({
    isAuthenticated: false,
    user: null,
  });
  const [isIntakeMode, setIsIntakeMode] = useState(false);

  const { config, result, isRunning, progress, updateConfig, runSimulation } = useSimulation();

  // Check URL for ?intake=true ΓÇö this is what the QR code links to
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    if (params.get('intake') === 'true') {
      setIsIntakeMode(true);
    }
  }, []);

  const handleLogout = () => {
    setLoginState({ isAuthenticated: false, user: null });
  };

  const handleBackFromIntake = () => {
    const url = new URL(window.location.href);
    url.searchParams.delete('intake');
    window.history.replaceState({}, '', url.toString());
    setIsIntakeMode(false);
  };

  // ΓöÇΓöÇ Patient Intake Form (accessed via QR code scan) ΓöÇΓöÇ
  if (isIntakeMode) {
    return <PatientIntakeForm onBack={handleBackFromIntake} />;
  }

  // ΓöÇΓöÇ Login Page ΓöÇΓöÇ
  if (!loginState.isAuthenticated) {
    return <LoginPage onLogin={setLoginState} />;
  }

  // ΓöÇΓöÇ Neumorphic Dashboard ΓöÇΓöÇ
  return (
    <NeuDashboard
      user={loginState.user}
      onLogout={handleLogout}
      config={config}
      result={result}
      isRunning={isRunning}
      progress={progress}
      updateConfig={updateConfig}
      runSimulation={runSimulation}
    />
  );
}

export default App;

// Patient Arrival Rate ΓÇö Area Chart with surge peaks
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend,
  ReferenceArea
} from 'recharts';
import type { HourlyStats } from '../../simulation/types';

interface ArrivalChartProps {
  hourlyStats: HourlyStats[];
}

export default function ArrivalChart({ hourlyStats }: ArrivalChartProps) {
  const surgeHours = hourlyStats.filter(h => h.isSurge).map(h => h.hour);

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const stat = hourlyStats.find(h => h.hour === label);
      return (
        <div className="bg-slate-800 border border-slate-600 rounded-lg px-3 py-2 shadow-xl">
          <p className="text-sm font-semibold text-white">Hour {label}</p>
          <p className="text-xs text-cyan-400">
            Arrivals: {payload[0]?.value} patients
          </p>
          {stat?.isSurge && (
            <p className="text-[10px] text-red-400 mt-1">
              ≡ƒÜ¿ Surge event ΓÇö arrival rate multiplied by 2.5├ù
            </p>
          )}
          <p className="text-[10px] text-slate-500 mt-1">
            Patient arrivals follow a Poisson distribution
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="glass-card p-4 animate-fade-in-up" style={{ animationDelay: '0.3s' }}>
      <h3 className="text-sm font-semibold text-white mb-1">Patient Arrival Rate</h3>
      <p className="text-[10px] text-slate-500 mb-3">Arrivals per hour (Poisson distributed, surge peaks highlighted)</p>
      <ResponsiveContainer width="100%" height={220}>
        <AreaChart data={hourlyStats}>
          <defs>
            <linearGradient id="arrivalGradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#06b6d4" stopOpacity={0.4} />
              <stop offset="95%" stopColor="#06b6d4" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
          <XAxis
            dataKey="hour"
            stroke="#64748b"
            tick={{ fontSize: 11 }}
            label={{ value: 'Hour', position: 'insideBottomRight', offset: -5, style: { fontSize: 10, fill: '#64748b' } }}
          />
          <YAxis
            stroke="#64748b"
            tick={{ fontSize: 11 }}
            label={{ value: 'Patients', angle: -90, position: 'insideLeft', style: { fontSize: 10, fill: '#64748b' } }}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend
            formatter={() => <span className="text-xs text-slate-400">Arrivals / Hour</span>}
          />
          {surgeHours.map(h => (
            <ReferenceArea
              key={h}
              x1={h - 0.4}
              x2={h + 0.4}
              fill="#ff4444"
              fillOpacity={0.1}
              strokeOpacity={0}
            />
          ))}
          <Area
            type="monotone"
            dataKey="arrivals"
            stroke="#06b6d4"
            strokeWidth={2}
            fill="url(#arrivalGradient)"
            dot={{ fill: '#06b6d4', r: 3, strokeWidth: 0 }}
            activeDot={{ r: 6, fill: '#06b6d4', stroke: '#0a0f1e', strokeWidth: 2 }}
            animationDuration={800}
            animationEasing="ease-out"
            name="Arrivals"
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

// Monte Carlo Output ΓÇö Line chart with confidence interval band + animated stats
import {
  ComposedChart, Line, Area, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, Legend
} from 'recharts';
import type { MonteCarloOutput } from '../../simulation/types';
import { useCountUp } from '../../hooks/useCountUp';

interface MonteCarloChartProps {
  mcData: MonteCarloOutput;
}

// Animated stat cell for the Monte Carlo stats row
function MCStatCell({
  value,
  suffix,
  prefix,
  decimals,
  label,
  color,
  delay,
}: {
  value: number;
  suffix?: string;
  prefix?: string;
  decimals?: number;
  label: string;
  color: string;
  delay: number;
}) {
  const { count, ref, hasStarted } = useCountUp({
    end: value,
    duration: 1800,
    delay,
    decimals: decimals ?? 1,
  });

  return (
    <div ref={ref} className="text-center p-2 rounded-lg bg-slate-800/50">
      <div
        className={`text-lg font-bold ${color} tabular-nums transition-all duration-500 ${
          hasStarted ? 'translate-y-0 opacity-100 scale-100' : 'translate-y-2 opacity-0 scale-90'
        }`}
        style={{ transitionTimingFunction: 'cubic-bezier(0.34, 1.56, 0.64, 1)' }}
      >
        {prefix}{count}{suffix}
      </div>
      <div className="text-[10px] text-slate-500">{label}</div>
    </div>
  );
}

export default function MonteCarloChart({ mcData }: MonteCarloChartProps) {
  // Sample iterations for display (show every 10th point for performance)
  const sampledData = mcData.iterationData
    .filter((_, i) => i % 5 === 0 || i === mcData.iterationData.length - 1)
    .map(d => ({
      ...d,
      upperBound: mcData.avgWaitTimeUpper,
      lowerBound: mcData.avgWaitTimeLower,
      mean: mcData.avgWaitTimeMean,
    }));

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-slate-800 border border-slate-600 rounded-lg px-3 py-2 shadow-xl">
          <p className="text-sm font-semibold text-white">Iteration #{label}</p>
          <p className="text-xs text-amber-400">
            Wait Time: {payload[0]?.value?.toFixed(1)} min
          </p>
          <p className="text-xs text-emerald-400">
            Mean: {mcData.avgWaitTimeMean.toFixed(1)} min
          </p>
          <p className="text-[10px] text-slate-500 mt-1">
            95% CI: [{mcData.avgWaitTimeLower.toFixed(1)} ΓÇô {mcData.avgWaitTimeUpper.toFixed(1)}] min
          </p>
          <p className="text-[10px] text-slate-500">
            Each iteration uses the same config but different random seed
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="glass-card p-4 animate-fade-in-up" style={{ animationDelay: '0.4s' }}>
      <div className="flex items-center justify-between mb-1">
        <h3 className="text-sm font-semibold text-white">Monte Carlo Analysis</h3>
        <span className="text-[10px] px-2 py-0.5 rounded-full bg-amber-500/20 text-amber-400 border border-amber-500/30">
          {mcData.iterations} iterations
        </span>
      </div>
      <p className="text-[10px] text-slate-500 mb-3">
        Wait time distribution with 95% confidence interval band
      </p>
      <ResponsiveContainer width="100%" height={220}>
        <ComposedChart data={sampledData}>
          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
          <XAxis
            dataKey="iteration"
            stroke="#64748b"
            tick={{ fontSize: 10 }}
            label={{ value: 'Iteration', position: 'insideBottomRight', offset: -5, style: { fontSize: 10, fill: '#64748b' } }}
          />
          <YAxis
            stroke="#64748b"
            tick={{ fontSize: 10 }}
            label={{ value: 'Wait (min)', angle: -90, position: 'insideLeft', style: { fontSize: 10, fill: '#64748b' } }}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend
            formatter={(value: string) => (
              <span className="text-xs text-slate-400">
                {value === 'avgWaitTime' ? 'Iteration Result' : value === 'mean' ? 'Mean' : '95% CI Band'}
              </span>
            )}
          />
          {/* CI Band */}
          <Area
            type="monotone"
            dataKey="upperBound"
            stroke="none"
            fill="#f59e0b"
            fillOpacity={0.1}
            name="95% CI Band"
            animationDuration={800}
          />
          {/* Individual iteration line */}
          <Line
            type="monotone"
            dataKey="avgWaitTime"
            stroke="#f59e0b"
            strokeWidth={1.5}
            dot={false}
            name="avgWaitTime"
            animationDuration={800}
          />
          {/* Mean line */}
          <Line
            type="monotone"
            dataKey="mean"
            stroke="#00ff88"
            strokeWidth={2}
            strokeDasharray="5 5"
            dot={false}
            name="mean"
            animationDuration={800}
          />
        </ComposedChart>
      </ResponsiveContainer>

      {/* Stats row ΓÇö with count-up animations */}
      <div className="grid grid-cols-3 gap-2 mt-3">
        <MCStatCell
          value={mcData.avgWaitTimeMean}
          suffix="m"
          decimals={1}
          label="Mean Wait"
          color="text-emerald-400"
          delay={0}
        />
        <MCStatCell
          value={Math.round((mcData.avgWaitTimeUpper - mcData.avgWaitTimeMean) * 10) / 10}
          prefix="┬▒"
          suffix="m"
          decimals={1}
          label="95% CI"
          color="text-amber-400"
          delay={200}
        />
        <MCStatCell
          value={mcData.exhaustionMean}
          decimals={1}
          label="Avg Exhaustion"
          color="text-red-400"
          delay={400}
        />
      </div>
    </div>
  );
}

// Resource Utilization ΓÇö Grouped Bar Chart
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell
} from 'recharts';
import type { ResourceUtilization } from '../../simulation/types';

interface ResourceChartProps {
  utilization: ResourceUtilization;
}

export default function ResourceChart({ utilization }: ResourceChartProps) {
  const data = [
    {
      name: 'Doctors',
      Used: utilization.doctorsUsed,
      Available: utilization.doctorsAvailable,
      utilPercent: Math.round((utilization.doctorsUsed / utilization.doctorsAvailable) * 100),
    },
    {
      name: 'ICU Beds',
      Used: utilization.icuUsed,
      Available: utilization.icuAvailable,
      utilPercent: Math.round((utilization.icuUsed / utilization.icuAvailable) * 100),
    },
    {
      name: 'Ventilators',
      Used: utilization.ventilatorsUsed,
      Available: utilization.ventilatorsAvailable,
      utilPercent: Math.round((utilization.ventilatorsUsed / utilization.ventilatorsAvailable) * 100),
    },
  ];

  const getBarColor = (percent: number) => {
    if (percent >= 90) return '#ff4444';
    if (percent >= 70) return '#ff8c00';
    if (percent >= 50) return '#ffd700';
    return '#00ff88';
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const item = data.find(d => d.name === label);
      return (
        <div className="bg-slate-800 border border-slate-600 rounded-lg px-3 py-2 shadow-xl">
          <p className="text-sm font-semibold text-white">{label}</p>
          <p className="text-xs text-emerald-400">Used: {payload[0]?.value}</p>
          <p className="text-xs text-slate-400">Available: {payload[1]?.value}</p>
          <p className="text-xs mt-1" style={{ color: getBarColor(item?.utilPercent || 0) }}>
            {item?.utilPercent}% utilization
          </p>
          <p className="text-[10px] text-slate-500 mt-1">
            {label === 'Doctors' && 'Physicians assigned to treat patients based on priority'}
            {label === 'ICU Beds' && 'ICU beds reserved for P1 Critical patients only'}
            {label === 'Ventilators' && 'Assigned to respiratory failure and critical cases'}
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="glass-card p-4 animate-fade-in-up" style={{ animationDelay: '0.2s' }}>
      <h3 className="text-sm font-semibold text-white mb-1">Resource Utilization</h3>
      <p className="text-[10px] text-slate-500 mb-3">Used vs. available hospital resources</p>
      <ResponsiveContainer width="100%" height={220}>
        <BarChart data={data} barGap={4}>
          <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
          <XAxis dataKey="name" stroke="#64748b" tick={{ fontSize: 11 }} />
          <YAxis stroke="#64748b" tick={{ fontSize: 11 }} />
          <Tooltip content={<CustomTooltip />} />
          <Legend
            formatter={(value: string) => <span className="text-xs text-slate-400">{value}</span>}
          />
          <Bar dataKey="Used" radius={[4, 4, 0, 0]} animationDuration={800}>
            {data.map((entry, index) => (
              <Cell key={`used-${index}`} fill={getBarColor(entry.utilPercent)} />
            ))}
          </Bar>
          <Bar dataKey="Available" fill="#1e293b" radius={[4, 4, 0, 0]} animationDuration={800} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

// Patient Triage Breakdown ΓÇö Donut Chart
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import type { SimulationSummary } from '../../simulation/types';
import { TRIAGE_CONFIG } from '../../constants/medicalData';

interface TriageChartProps {
  summary: SimulationSummary;
}

const COLORS = [
  TRIAGE_CONFIG.P1.color,
  TRIAGE_CONFIG.P2.color,
  TRIAGE_CONFIG.P3.color,
  TRIAGE_CONFIG.P4.color,
];

export default function TriageChart({ summary }: TriageChartProps) {
  const data = [
    { name: 'P1 Critical', value: summary.triageBreakdown.p1, color: COLORS[0] },
    { name: 'P2 Urgent', value: summary.triageBreakdown.p2, color: COLORS[1] },
    { name: 'P3 Semi-Urgent', value: summary.triageBreakdown.p3, color: COLORS[2] },
    { name: 'P4 Non-Urgent', value: summary.triageBreakdown.p4, color: COLORS[3] },
  ];

  const total = data.reduce((s, d) => s + d.value, 0);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      const entry = payload[0];
      const percent = ((entry.value / total) * 100).toFixed(1);
      return (
        <div className="bg-slate-800 border border-slate-600 rounded-lg px-3 py-2 shadow-xl">
          <p className="text-sm font-semibold" style={{ color: entry.payload.color }}>
            {entry.name}
          </p>
          <p className="text-xs text-slate-300">
            {entry.value} patients ({percent}%)
          </p>
          <p className="text-[10px] text-slate-500 mt-1">
            {entry.name.includes('Critical') && 'Highest priority ΓÇö life-threatening conditions'}
            {entry.name.includes('Urgent') && 'High priority ΓÇö requires rapid treatment'}
            {entry.name.includes('Semi') && 'Moderate priority ΓÇö stable but needs attention'}
            {entry.name.includes('Non') && 'Low priority ΓÇö can safely wait'}
          </p>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="glass-card p-4 animate-fade-in-up">
      <h3 className="text-sm font-semibold text-white mb-1">Triage Breakdown</h3>
      <p className="text-[10px] text-slate-500 mb-3">Distribution of patient severity levels</p>
      <ResponsiveContainer width="100%" height={220}>
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={55}
            outerRadius={85}
            paddingAngle={3}
            dataKey="value"
            animationBegin={0}
            animationDuration={800}
            animationEasing="ease-out"
          >
            {data.map((_entry, index) => (
              <Cell key={`cell-${index}`} fill={COLORS[index]} stroke="none" />
            ))}
          </Pie>
          <Tooltip content={<CustomTooltip />} />
          <Legend
            verticalAlign="bottom"
            height={36}
            formatter={(value: string) => <span className="text-xs text-slate-400">{value}</span>}
          />
        </PieChart>
      </ResponsiveContainer>
      {/* Center label */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none" style={{ marginTop: '-20px' }}>
        <div className="text-center">
          <div className="text-2xl font-bold text-white">{total}</div>
          <div className="text-[10px] text-slate-500">Total</div>
        </div>
      </div>
    </div>
  );
}

// Waiting Time Over Simulation Hours ΓÇö Line Chart with surge highlighting
