              x1={h - 0.4}
              x2={h + 0.4}
              fill="#ff4444"
              fillOpacity={0.08}
              strokeOpacity={0}
            />
          ))}
          <Line
            type="monotone"
            dataKey="avgWaitTime"
            stroke="#00ff88"
            strokeWidth={2.5}
            dot={{ fill: '#00ff88', r: 3, strokeWidth: 0 }}
            activeDot={{ r: 6, fill: '#00ff88', stroke: '#0a0f1e', strokeWidth: 2 }}
            animationDuration={800}
            animationEasing="ease-out"
            name="Avg Wait Time"
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

