// GhostCursor ΓÇö Fluid smoky cursor trail effect using Three.js
// Adapted for SmartER medical theme with neon green trail
import { useEffect, useMemo, useRef } from 'react';
import * as THREE from 'three';
import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer.js';
import { RenderPass } from 'three/examples/jsm/postprocessing/RenderPass.js';
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass.js';
import { ShaderPass } from 'three/examples/jsm/postprocessing/ShaderPass.js';

type GhostCursorProps = {
  className?: string;
  style?: React.CSSProperties;
  trailLength?: number;
  inertia?: number;
  grainIntensity?: number;
  bloomStrength?: number;
  bloomRadius?: number;
  bloomThreshold?: number;
  brightness?: number;
  color?: string;
  mixBlendMode?: React.CSSProperties['mixBlendMode'];
  edgeIntensity?: number;
  maxDevicePixelRatio?: number;
  targetPixels?: number;
  fadeDelayMs?: number;
  fadeDurationMs?: number;
  zIndex?: number;
};

export const GhostCursor: React.FC<GhostCursorProps> = ({
  className,
  style,
  trailLength = 50,
  inertia = 0.5,
  grainIntensity = 0.05,
  bloomStrength = 0.1,
  bloomRadius = 1.0,
  bloomThreshold = 0.025,
  brightness = 1,
  color = '#B19EEF',
  mixBlendMode = 'screen',
  edgeIntensity = 0,
  maxDevicePixelRatio = 0.5,
  targetPixels,
  fadeDelayMs,
  fadeDurationMs,
  zIndex = 10
}) => {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const composerRef = useRef<EffectComposer | null>(null);
  const materialRef = useRef<THREE.ShaderMaterial | null>(null);
  const bloomPassRef = useRef<UnrealBloomPass | null>(null);
  const filmPassRef = useRef<ShaderPass | null>(null);

  const trailBufRef = useRef<THREE.Vector2[]>([]);
  const headRef = useRef(0);
  const rafRef = useRef<number | null>(null);
  const resizeObsRef = useRef<ResizeObserver | null>(null);
  const currentMouseRef = useRef(new THREE.Vector2(0.5, 0.5));
  const velocityRef = useRef(new THREE.Vector2(0, 0));
  const fadeOpacityRef = useRef(1.0);
  const lastMoveTimeRef = useRef(typeof performance !== 'undefined' ? performance.now() : Date.now());
  const pointerActiveRef = useRef(false);
  const runningRef = useRef(false);

  const isTouch = useMemo(
    () => typeof window !== 'undefined' && ('ontouchstart' in window || navigator.maxTouchPoints > 0),
    []
  );

  const pixelBudget = targetPixels ?? (isTouch ? 0.9e6 : 1.3e6);
  const fadeDelay = fadeDelayMs ?? (isTouch ? 500 : 1000);
  const fadeDuration = fadeDurationMs ?? (isTouch ? 1000 : 1500);

  const baseVertexShader = `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = vec4(position, 1.0);
    }
  `;

  const fragmentShader = `
    uniform float iTime;
    uniform vec3  iResolution;
    uniform vec2  iMouse;
    uniform vec2  iPrevMouse[MAX_TRAIL_LENGTH];
    uniform float iOpacity;
    uniform float iScale;
    uniform vec3  iBaseColor;
    uniform float iBrightness;
    uniform float iEdgeIntensity;
    varying vec2  vUv;

    float hash(vec2 p){ return fract(sin(dot(p,vec2(127.1,311.7))) * 43758.5453123); }
    float noise(vec2 p){
      vec2 i = floor(p), f = fract(p);
      f = f * f * (3. - 2. * f);
      return mix(mix(hash(i + vec2(0.,0.)), hash(i + vec2(1.,0.)), f.x),
                 mix(hash(i + vec2(0.,1.)), hash(i + vec2(1.,1.)), f.x), f.y);
    }
    float fbm(vec2 p){
      float v = 0.0; float a = 0.5;
      mat2 m = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
      for(int i=0;i<5;i++){ v += a * noise(p); p = m * p * 2.0; a *= 0.5; }
      return v;
    }
    vec3 tint1(vec3 base){ return mix(base, vec3(1.0), 0.15); }
    vec3 tint2(vec3 base){ return mix(base, vec3(0.8, 0.9, 1.0), 0.25); }
    vec4 blob(vec2 p, vec2 mousePos, float intensity, float activity) {
      vec2 q = vec2(fbm(p * iScale + iTime * 0.1), fbm(p * iScale + vec2(5.2,1.3) + iTime * 0.1));
      vec2 r = vec2(fbm(p * iScale + q * 1.5 + iTime * 0.15), fbm(p * iScale + q * 1.5 + vec2(8.3,2.8) + iTime * 0.15));
      float smoke = fbm(p * iScale + r * 0.8);
      float radius = 0.5 + 0.3 * (1.0 / iScale);
      float distFactor = 1.0 - smoothstep(0.0, radius * activity, length(p - mousePos));
      float alpha = pow(smoke, 2.5) * distFactor;
      vec3 c1 = tint1(iBaseColor); vec3 c2 = tint2(iBaseColor);
      vec3 color = mix(c1, c2, sin(iTime * 0.5) * 0.5 + 0.5);
      return vec4(color * alpha * intensity, alpha * intensity);
    }
    void main() {
      vec2 uv = (gl_FragCoord.xy / iResolution.xy * 2.0 - 1.0) * vec2(iResolution.x / iResolution.y, 1.0);
      vec2 mouse = (iMouse * 2.0 - 1.0) * vec2(iResolution.x / iResolution.y, 1.0);
      vec3 colorAcc = vec3(0.0); float alphaAcc = 0.0;
      vec4 b = blob(uv, mouse, 1.0, iOpacity);
      colorAcc += b.rgb; alphaAcc += b.a;
      for (int i = 0; i < MAX_TRAIL_LENGTH; i++) {
        vec2 pm = (iPrevMouse[i] * 2.0 - 1.0) * vec2(iResolution.x / iResolution.y, 1.0);
        float t = 1.0 - float(i) / float(MAX_TRAIL_LENGTH);
        t = pow(t, 2.0);
        if (t > 0.01) { vec4 bt = blob(uv, pm, t * 0.8, iOpacity); colorAcc += bt.rgb; alphaAcc += bt.a; }
      }
      colorAcc *= iBrightness;
      vec2 uv01 = gl_FragCoord.xy / iResolution.xy;
      float edgeDist = min(min(uv01.x, 1.0 - uv01.x), min(uv01.y, 1.0 - uv01.y));
      float distFromEdge = clamp(edgeDist * 2.0, 0.0, 1.0);
      float k = clamp(iEdgeIntensity, 0.0, 1.0);
      float edgeMask = mix(1.0 - k, 1.0, distFromEdge);
      float outAlpha = clamp(alphaAcc * iOpacity * edgeMask, 0.0, 1.0);
      gl_FragColor = vec4(colorAcc, outAlpha);
    }
  `;

  const FilmGrainShader = useMemo(() => ({
    uniforms: { tDiffuse: { value: null }, iTime: { value: 0 }, intensity: { value: grainIntensity } },
    vertexShader: `varying vec2 vUv; void main(){ vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }`,
    fragmentShader: `
      uniform sampler2D tDiffuse; uniform float iTime; uniform float intensity; varying vec2 vUv;
      float hash1(float n){ return fract(sin(n)*43758.5453); }
      void main(){ vec4 color = texture2D(tDiffuse, vUv); float n = hash1(vUv.x*1000.0 + vUv.y*2000.0 + iTime) * 2.0 - 1.0; color.rgb += n * intensity * color.rgb; gl_FragColor = color; }
    `
  }), [grainIntensity]);

  const UnpremultiplyPass = useMemo(() => new ShaderPass({
    uniforms: { tDiffuse: { value: null } },
    vertexShader: `varying vec2 vUv; void main(){ vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }`,
    fragmentShader: `uniform sampler2D tDiffuse; varying vec2 vUv; void main(){ vec4 c = texture2D(tDiffuse, vUv); float a = max(c.a, 1e-5); vec3 straight = c.rgb / a; gl_FragColor = vec4(clamp(straight, 0.0, 1.0), c.a); }`
  }), []);

  function calculateScale(el: HTMLElement) {
    const r = el.getBoundingClientRect();
    const base = 600;
    const current = Math.min(Math.max(1, r.width), Math.max(1, r.height));
    return Math.max(0.5, Math.min(2.0, current / base));
  }

  useEffect(() => {
    const host = containerRef.current;
    const parent = host?.parentElement;
    if (!host || !parent) return;

    const renderer = new THREE.WebGLRenderer({
      antialias: !isTouch, alpha: true, depth: false, stencil: false,
      powerPreference: 'default', premultipliedAlpha: false, preserveDrawingBuffer: false
    });
    renderer.setClearColor(0x000000, 0);
    rendererRef.current = renderer;
    renderer.domElement.style.pointerEvents = 'none';
    if (mixBlendMode) renderer.domElement.style.mixBlendMode = String(mixBlendMode);
    renderer.domElement.style.display = 'block';
    renderer.domElement.style.width = '100%';
    renderer.domElement.style.height = '100%';
    renderer.domElement.style.background = 'transparent';
    host.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    const geom = new THREE.PlaneGeometry(2, 2);
    const maxTrail = Math.max(1, Math.floor(trailLength));
    trailBufRef.current = Array.from({ length: maxTrail }, () => new THREE.Vector2(0.5, 0.5));
    headRef.current = 0;

    const baseColor = new THREE.Color(color);
    const material = new THREE.ShaderMaterial({
      defines: { MAX_TRAIL_LENGTH: maxTrail },
      uniforms: {
        iTime: { value: 0 }, iResolution: { value: new THREE.Vector3(1, 1, 1) },
        iMouse: { value: new THREE.Vector2(0.5, 0.5) },
        iPrevMouse: { value: trailBufRef.current.map(v => v.clone()) },
        iOpacity: { value: 1.0 }, iScale: { value: 1.0 },
        iBaseColor: { value: new THREE.Vector3(baseColor.r, baseColor.g, baseColor.b) },
        iBrightness: { value: brightness }, iEdgeIntensity: { value: edgeIntensity }
      },
      vertexShader: baseVertexShader, fragmentShader, transparent: true, depthTest: false, depthWrite: false
    });
    materialRef.current = material;
    scene.add(new THREE.Mesh(geom, material));

    const composer = new EffectComposer(renderer);
    composerRef.current = composer;
    composer.addPass(new RenderPass(scene, camera));
    const bloomPass = new UnrealBloomPass(new THREE.Vector2(1, 1), bloomStrength, bloomRadius, bloomThreshold);
    bloomPassRef.current = bloomPass;
    composer.addPass(bloomPass);
    const filmPass = new ShaderPass(FilmGrainShader as any);
    filmPassRef.current = filmPass;
    composer.addPass(filmPass);
    composer.addPass(UnpremultiplyPass);

    const resize = () => {
      const rect = host.getBoundingClientRect();
      const cssW = Math.max(1, Math.floor(rect.width));
      const cssH = Math.max(1, Math.floor(rect.height));
      const currentDPR = Math.min(window.devicePixelRatio || 1, maxDevicePixelRatio);
      const need = cssW * cssH * currentDPR * currentDPR;
      const scale = need <= pixelBudget ? 1 : Math.max(0.5, Math.min(1, Math.sqrt(pixelBudget / Math.max(1, need))));
      const pixelRatio = currentDPR * scale;
      renderer.setPixelRatio(pixelRatio);
      renderer.setSize(cssW, cssH, false);
      composer.setSize(cssW, cssH);
      const wpx = Math.max(1, Math.floor(cssW * pixelRatio));
      const hpx = Math.max(1, Math.floor(cssH * pixelRatio));
      material.uniforms.iResolution.value.set(wpx, hpx, 1);
      material.uniforms.iScale.value = calculateScale(host);
      bloomPass.setSize(wpx, hpx);
    };

    resize();
    const ro = new ResizeObserver(resize);
    resizeObsRef.current = ro;
    ro.observe(host);

    const start = performance.now();
    const animate = () => {
      const now = performance.now();
      const t = (now - start) / 1000;
      const mat = materialRef.current!;
      const comp = composerRef.current!;

      if (pointerActiveRef.current) {
        velocityRef.current.set(
          currentMouseRef.current.x - mat.uniforms.iMouse.value.x,
          currentMouseRef.current.y - mat.uniforms.iMouse.value.y
        );
        mat.uniforms.iMouse.value.copy(currentMouseRef.current);
        fadeOpacityRef.current = 1.0;
      } else {
        velocityRef.current.multiplyScalar(inertia);
        if (velocityRef.current.lengthSq() > 1e-6) mat.uniforms.iMouse.value.add(velocityRef.current);
        const dt = now - lastMoveTimeRef.current;
        if (dt > fadeDelay) {
          const k = Math.min(1, (dt - fadeDelay) / fadeDuration);
          fadeOpacityRef.current = Math.max(0, 1 - k);
        }
      }

      const N = trailBufRef.current.length;
      headRef.current = (headRef.current + 1) % N;
      trailBufRef.current[headRef.current].copy(mat.uniforms.iMouse.value);
      const arr = mat.uniforms.iPrevMouse.value as THREE.Vector2[];
      for (let i = 0; i < N; i++) {
        const srcIdx = (headRef.current - i + N) % N;
        arr[i].copy(trailBufRef.current[srcIdx]);
      }
      mat.uniforms.iOpacity.value = fadeOpacityRef.current;
      mat.uniforms.iTime.value = t;
      if (filmPassRef.current?.uniforms?.iTime) filmPassRef.current.uniforms.iTime.value = t;
      comp.render();
      if (!pointerActiveRef.current && fadeOpacityRef.current <= 0.001) {
        runningRef.current = false; rafRef.current = null; return;
      }
      rafRef.current = requestAnimationFrame(animate);
    };

    const ensureLoop = () => { if (!runningRef.current) { runningRef.current = true; rafRef.current = requestAnimationFrame(animate); } };

    const onPointerMove = (e: PointerEvent) => {
      const rect = parent.getBoundingClientRect();
      const x = THREE.MathUtils.clamp((e.clientX - rect.left) / Math.max(1, rect.width), 0, 1);
      const y = THREE.MathUtils.clamp(1 - (e.clientY - rect.top) / Math.max(1, rect.height), 0, 1);
      currentMouseRef.current.set(x, y);
      pointerActiveRef.current = true;
      lastMoveTimeRef.current = performance.now();
      ensureLoop();
    };
    const onPointerEnter = () => { pointerActiveRef.current = true; ensureLoop(); };
    const onPointerLeave = () => { pointerActiveRef.current = false; lastMoveTimeRef.current = performance.now(); ensureLoop(); };

    parent.addEventListener('pointermove', onPointerMove, { passive: true });
    parent.addEventListener('pointerenter', onPointerEnter, { passive: true });
    parent.addEventListener('pointerleave', onPointerLeave, { passive: true });
    ensureLoop();

    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
      runningRef.current = false; rafRef.current = null;
      parent.removeEventListener('pointermove', onPointerMove);
      parent.removeEventListener('pointerenter', onPointerEnter);
      parent.removeEventListener('pointerleave', onPointerLeave);
      resizeObsRef.current?.disconnect();
      scene.clear(); geom.dispose(); material.dispose(); composer.dispose(); renderer.dispose();
      if (renderer.domElement?.parentElement) renderer.domElement.parentElement.removeChild(renderer.domElement);
    };
  }, [trailLength, inertia, grainIntensity, bloomStrength, bloomRadius, bloomThreshold, pixelBudget, fadeDelay, fadeDuration, isTouch, color, brightness, mixBlendMode, edgeIntensity]);

  useEffect(() => { if (materialRef.current) { const c = new THREE.Color(color); (materialRef.current.uniforms.iBaseColor.value as THREE.Vector3).set(c.r, c.g, c.b); } }, [color]);
  useEffect(() => { if (materialRef.current) materialRef.current.uniforms.iBrightness.value = brightness; }, [brightness]);
  useEffect(() => { if (materialRef.current) materialRef.current.uniforms.iEdgeIntensity.value = edgeIntensity; }, [edgeIntensity]);
  useEffect(() => { if (filmPassRef.current?.uniforms?.intensity) filmPassRef.current.uniforms.intensity.value = grainIntensity; }, [grainIntensity]);
  useEffect(() => { const el = rendererRef.current?.domElement; if (!el) return; if (mixBlendMode) el.style.mixBlendMode = String(mixBlendMode); else el.style.removeProperty('mix-blend-mode'); }, [mixBlendMode]);

  const mergedStyle = useMemo<React.CSSProperties>(() => ({ zIndex, ...style }), [zIndex, style]);

  return <div ref={containerRef} className={`pointer-events-none absolute inset-0 ${className ?? ''}`} style={mergedStyle} />;
};

export default GhostCursor;

// PatientIntakeForm ΓÇö Mobile-first form for patient self-registration via QR code
// Patients scan the QR code and fill in their details on their phone
// Now powered by Supabase for real-time cross-device sync
import React, { useState } from 'react';
import type { PatientRequest } from '../simulation/types';
import {
  Heart, User, Phone, AlertCircle, FileText, CheckCircle2,
  ArrowLeft, Stethoscope, Activity, Shield, Cloud
} from 'lucide-react';
import { supabase } from '../lib/supabase';

interface PatientIntakeFormProps {
  onBack?: () => void; // Go back to main app (only if on same device)
}

export default function PatientIntakeForm({ onBack }: PatientIntakeFormProps) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [formData, setFormData] = useState({
    name: '',
    age: '',
    gender: 'Prefer not to say' as PatientRequest['gender'],
    phone: '',
    symptoms: '',
    painLevel: 5,
    allergies: '',
    existingConditions: '',
    urgencyLevel: 'Standard' as PatientRequest['urgencyLevel'],
  });

  const updateField = (field: string, value: string | number) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSubmitError('');

    const requestId = `REQ-${Date.now().toString(36).toUpperCase()}`;

    try {
      // Insert into Supabase
      const { error } = await supabase.from('patient_requests').insert({
        id: requestId,
        name: formData.name,
        age: parseInt(formData.age) || 0,
        gender: formData.gender,
        phone: formData.phone,
        symptoms: formData.symptoms,
        pain_level: formData.painLevel,
        allergies: formData.allergies,
        existing_conditions: formData.existingConditions,
        urgency_level: formData.urgencyLevel,
        status: 'Pending',
      });

      if (error) throw error;

      setIsSubmitting(false);
      setIsSubmitted(true);
    } catch (err: any) {
      console.error('Supabase insert error:', err);
      // Fallback to localStorage
      const request: PatientRequest = {
        id: requestId,
        name: formData.name,
        age: parseInt(formData.age) || 0,
        gender: formData.gender,
        phone: formData.phone,
        symptoms: formData.symptoms,
        painLevel: formData.painLevel,
        allergies: formData.allergies,
        existingConditions: formData.existingConditions,
        urgencyLevel: formData.urgencyLevel,
        timestamp: Date.now(),
        status: 'Pending',
      };
      const existing = JSON.parse(localStorage.getItem('smarter-patient-requests') || '[]');
      existing.push(request);
      localStorage.setItem('smarter-patient-requests', JSON.stringify(existing));

      setIsSubmitting(false);
      setIsSubmitted(true);
      setSubmitError('Saved locally (cloud sync unavailable)');
    }
  };

  const urgencyColors = {
    Emergency: 'border-red-500/50 bg-red-500/10 text-red-400',
    Urgent: 'border-amber-500/50 bg-amber-500/10 text-amber-400',
    Standard: 'border-emerald-500/50 bg-emerald-500/10 text-emerald-400',
  };

  const isStep1Valid = formData.name.trim() && formData.age && parseInt(formData.age) > 0 && parseInt(formData.age) <= 120;
  const isStep2Valid = formData.symptoms.trim().length > 2;

  // ΓöÇΓöÇ Success Screen ΓöÇΓöÇ
  if (isSubmitted) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-[#0a0f1e] via-[#0f172a] to-[#0a0f1e] flex items-center justify-center p-4">
        <div className="w-full max-w-md text-center animate-fade-in-up">
          <div className="glass-card p-8 rounded-2xl">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-emerald-500/20 border-2 border-emerald-500/40 mb-6 mx-auto">
              <CheckCircle2 className="w-10 h-10 text-emerald-400" />
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">Request Submitted!</h2>
            <p className="text-slate-400 text-sm mb-6">
              Your details have been sent to the ER triage team. Please wait in the reception area ΓÇö a nurse will call your name shortly.
            </p>
            <div className="bg-slate-800/50 rounded-xl p-4 mb-6 text-left space-y-2">
              <div className="flex justify-between">
                <span className="text-xs text-slate-500">Patient</span>
                <span className="text-xs text-white font-medium">{formData.name}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-xs text-slate-500">Urgency</span>
                <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${urgencyColors[formData.urgencyLevel]}`}>
                  {formData.urgencyLevel}
                </span>
              </div>
              <div className="flex justify-between">
                <span className="text-xs text-slate-500">Pain Level</span>
                <span className="text-xs text-white">{formData.painLevel}/10</span>
              </div>
              <div className="flex justify-between">
                <span className="text-xs text-slate-500">Status</span>
                <span className="text-xs text-amber-400 font-medium">ΓÅ│ Pending Review</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs text-slate-500">Sync</span>
                <span className={`text-xs font-medium flex items-center gap-1 ${submitError ? 'text-amber-400' : 'text-emerald-400'}`}>
                  <Cloud className="w-3 h-3" />
                  {submitError ? 'Local only' : 'Cloud synced'}
                </span>
              </div>
            </div>
            <div className="space-y-3">
              <button
                onClick={() => { setIsSubmitted(false); setStep(1); setFormData(prev => ({ ...prev, name: '', age: '', symptoms: '' })); }}
                className="btn-neon w-full"
              >
                Submit Another Request
              </button>
              {onBack && (
                <button
                  onClick={onBack}
                  className="w-full py-3 rounded-lg border border-slate-700 text-slate-400 hover:text-white hover:border-slate-500 transition-all text-sm"
                >
                  Back to Dashboard
                </button>
              )}
            </div>
          </div>
          <p className="text-[10px] text-slate-600 mt-4">
            ≡ƒöÆ This is a simulated system ΓÇö no real patient data is stored
          </p>
        </div>
      </div>
    );
  }

  // ΓöÇΓöÇ Form ΓöÇΓöÇ
  return (
    <div className="min-h-screen bg-gradient-to-br from-[#0a0f1e] via-[#0f172a] to-[#0a0f1e] flex flex-col">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-[#0a0f1e]/90 backdrop-blur-lg border-b border-slate-800/50">
        <div className="max-w-md mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2">
            {onBack && (
              <button
                onClick={onBack}
                className="w-9 h-9 flex items-center justify-center rounded-lg bg-slate-800/50 border border-slate-700/50 text-slate-400 hover:text-white transition-colors"
              >
                <ArrowLeft className="w-4 h-4" />
              </button>
            )}
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-emerald-400/20 to-cyan-400/20 border border-emerald-500/30 flex items-center justify-center">
              <Heart className="w-4 h-4 text-emerald-400" />
            </div>
            <div>
              <h1 className="text-sm font-bold text-white">
                Smart<span className="text-emerald-400">ER</span>
              </h1>
              <p className="text-[8px] text-slate-500">Patient Intake Form</p>
            </div>
          </div>
          <Shield className="w-4 h-4 text-emerald-400/50" />
        </div>
      </header>

      {/* Progress bar */}
      <div className="max-w-md mx-auto w-full px-4 pt-4">
        <div className="flex gap-2 mb-1">
          {[1, 2, 3].map(s => (
            <div key={s} className="flex-1 h-1.5 rounded-full overflow-hidden bg-slate-800">
              <div
                className={`h-full rounded-full transition-all duration-500 ${
                  s <= step ? 'bg-emerald-400' : 'bg-slate-700'
                }`}
                style={{ width: s <= step ? '100%' : '0%' }}
              />
            </div>
          ))}
        </div>
        <p className="text-[10px] text-slate-500 mb-4">Step {step} of 3</p>
      </div>

      {/* Form Content */}
      <form onSubmit={handleSubmit} className="flex-1 max-w-md mx-auto w-full px-4 pb-6">
        {/* ΓöÇΓöÇ STEP 1: Personal Info ΓöÇΓöÇ */}
        {step === 1 && (
          <div className="space-y-4 animate-fade-in-up">
            <div className="flex items-center gap-2 mb-4">
              <User className="w-5 h-5 text-emerald-400" />
              <h2 className="text-lg font-semibold text-white">Personal Information</h2>
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Full Name *</label>
              <input
                type="text"
                value={formData.name}
                onChange={e => updateField('name', e.target.value)}
                placeholder="Enter your full name"
                className="login-input"
                required
                autoFocus
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs text-slate-400 mb-1.5">Age *</label>
                <input
                  type="number"
                  value={formData.age}
                  onChange={e => updateField('age', e.target.value)}
                  placeholder="Age"
                  min="1"
                  max="120"
                  className="login-input"
                  required
                />
              </div>
              <div>
                <label className="block text-xs text-slate-400 mb-1.5">Gender</label>
                <select
                  value={formData.gender}
                  onChange={e => updateField('gender', e.target.value)}
                  className="login-input"
                >
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
                  <option value="Prefer not to say">Prefer not to say</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Phone Number</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <Phone className="w-4 h-4 text-slate-500" />
                </div>
                <input
                  type="tel"
                  value={formData.phone}
                  onChange={e => updateField('phone', e.target.value)}
                  placeholder="+1 (555) 123-4567"
                  className="login-input pl-11"
                />
              </div>
            </div>

            <button
              type="button"
              onClick={() => setStep(2)}
              disabled={!isStep1Valid}
              className="btn-neon w-full mt-4"
            >
              Next ΓÇö Symptoms
            </button>
          </div>
        )}

        {/* ΓöÇΓöÇ STEP 2: Symptoms & Pain ΓöÇΓöÇ */}
        {step === 2 && (
          <div className="space-y-4 animate-fade-in-up">
            <div className="flex items-center gap-2 mb-4">
              <Stethoscope className="w-5 h-5 text-emerald-400" />
              <h2 className="text-lg font-semibold text-white">Symptoms & Pain Level</h2>
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Describe Your Symptoms *</label>
              <textarea
                value={formData.symptoms}
                onChange={e => updateField('symptoms', e.target.value)}
                placeholder="e.g., chest pain, difficulty breathing, headache, injury..."
                className="login-input min-h-[100px] resize-none"
                rows={4}
                required
                autoFocus
              />
            </div>

            {/* Pain Level Slider */}
            <div>
              <label className="block text-xs text-slate-400 mb-2">
                Pain Level: <span className={`font-bold ${
                  formData.painLevel >= 8 ? 'text-red-400' :
                  formData.painLevel >= 5 ? 'text-amber-400' : 'text-emerald-400'
                }`}>{formData.painLevel}/10</span>
              </label>
              <input
                type="range"
                min="1"
                max="10"
                value={formData.painLevel}
                onChange={e => updateField('painLevel', parseInt(e.target.value))}
                className="w-full"
              />
              <div className="flex justify-between text-[10px] text-slate-600 mt-1">
                <span>Mild</span>
                <span>Moderate</span>
                <span>Severe</span>
              </div>
            </div>

            {/* Urgency Selection */}
            <div>
              <label className="block text-xs text-slate-400 mb-2">How urgent is your situation?</label>
              <div className="grid grid-cols-3 gap-2">
                {(['Standard', 'Urgent', 'Emergency'] as const).map(level => (
                  <button
                    key={level}
                    type="button"
                    onClick={() => updateField('urgencyLevel', level)}
                    className={`py-3 px-2 rounded-xl border text-xs font-bold transition-all ${
                      formData.urgencyLevel === level
                        ? urgencyColors[level] + ' ring-2 ring-offset-2 ring-offset-[#0a0f1e] ' + (
                            level === 'Emergency' ? 'ring-red-500/50' :
                            level === 'Urgent' ? 'ring-amber-500/50' : 'ring-emerald-500/50'
                          )
                        : 'border-slate-700 bg-slate-800/30 text-slate-500 hover:border-slate-600'
                    }`}
                  >
                    {level === 'Emergency' ? '≡ƒÜ¿' : level === 'Urgent' ? 'ΓÜí' : '≡ƒƒó'} {level}
                  </button>
                ))}
              </div>
            </div>

            <div className="flex gap-3 mt-4">
              <button
                type="button"
                onClick={() => setStep(1)}
                className="flex-1 py-3 rounded-lg border border-slate-700 text-slate-400 hover:text-white hover:border-slate-500 transition-all text-sm"
              >
                Back
              </button>
              <button
                type="button"
                onClick={() => setStep(3)}
                disabled={!isStep2Valid}
                className="flex-1 btn-neon"
              >
                Next ΓÇö Medical History
              </button>
            </div>
          </div>
        )}

        {/* ΓöÇΓöÇ STEP 3: Medical History & Submit ΓöÇΓöÇ */}
        {step === 3 && (
          <div className="space-y-4 animate-fade-in-up">
            <div className="flex items-center gap-2 mb-4">
              <FileText className="w-5 h-5 text-emerald-400" />
              <h2 className="text-lg font-semibold text-white">Medical History</h2>
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Known Allergies</label>
              <input
                type="text"
                value={formData.allergies}
                onChange={e => updateField('allergies', e.target.value)}
                placeholder="e.g., penicillin, peanuts, latex... (None if N/A)"
                className="login-input"
                autoFocus
              />
            </div>

            <div>
              <label className="block text-xs text-slate-400 mb-1.5">Existing Medical Conditions</label>
              <textarea
                value={formData.existingConditions}
                onChange={e => updateField('existingConditions', e.target.value)}
                placeholder="e.g., diabetes, hypertension, asthma... (None if N/A)"
                className="login-input min-h-[80px] resize-none"
                rows={3}
              />
            </div>

            {/* Summary Preview */}
            <div className="bg-slate-800/50 rounded-xl p-4 border border-slate-700/30">
              <div className="flex items-center gap-2 mb-3">
                <Activity className="w-4 h-4 text-emerald-400" />
                <span className="text-xs font-semibold text-white">Request Preview</span>
              </div>
              <div className="space-y-2 text-xs">
                <div className="flex justify-between">
                  <span className="text-slate-500">Name</span>
                  <span className="text-white">{formData.name}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Age / Gender</span>
                  <span className="text-white">{formData.age} / {formData.gender}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Symptoms</span>
                  <span className="text-white text-right max-w-[200px] truncate">{formData.symptoms}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Pain Level</span>
                  <span className={`font-bold ${
                    formData.painLevel >= 8 ? 'text-red-400' :
                    formData.painLevel >= 5 ? 'text-amber-400' : 'text-emerald-400'
                  }`}>{formData.painLevel}/10</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-slate-500">Urgency</span>
                  <span className={`font-bold ${urgencyColors[formData.urgencyLevel]}`}>
                    {formData.urgencyLevel}
                  </span>
                </div>
              </div>
            </div>

            {/* Disclaimer */}
            <div className="flex items-start gap-2 px-3 py-2 rounded-lg bg-amber-500/10 border border-amber-500/20">
              <AlertCircle className="w-4 h-4 text-amber-400 flex-shrink-0 mt-0.5" />
              <p className="text-[10px] text-amber-300/80">
                If you are experiencing a life-threatening emergency, please inform the front desk immediately. Do not wait for digital processing.
              </p>
            </div>

            <div className="flex gap-3 mt-4">
              <button
                type="button"
                onClick={() => setStep(2)}
                className="flex-1 py-3 rounded-lg border border-slate-700 text-slate-400 hover:text-white hover:border-slate-500 transition-all text-sm"
              >
                Back
              </button>
              <button
                type="submit"
                disabled={isSubmitting}
                className="flex-1 btn-neon flex items-center justify-center gap-2"
              >
                {isSubmitting ? (
                  <>
                    <div className="w-4 h-4 border-2 border-slate-800/30 border-t-slate-800 rounded-full animate-spin" />
                    Submitting...
                  </>
                ) : (
                  <>
                    <CheckCircle2 className="w-4 h-4" />
                    Submit Request
                  </>
                )}
              </button>
            </div>
          </div>
        )}
      </form>

      {/* Footer */}
      <footer className="max-w-md mx-auto w-full px-4 py-3 text-center">
        <p className="text-[10px] text-slate-600">
          ≡ƒöÆ Simulated system ΓÇö No real patient data is collected or stored
        </p>
      </footer>
    </div>
  );
}

// QRCodePanel ΓÇö Displays a scannable QR code for patient self-registration
// Uses Supabase Realtime for cross-device live updates
import { useState, useEffect, useMemo } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import type { PatientRequest } from '../../simulation/types';
import { supabase, rowToPatientRequest } from '../../lib/supabase';
import type { PatientRequestRow } from '../../lib/supabase';
import { QrCode, RefreshCw, Trash2, Clock, AlertCircle, CheckCircle2, Eye, Cloud, CloudOff } from 'lucide-react';

interface QRCodePanelProps {
  className?: string;
}

export default function QRCodePanel({ className = '' }: QRCodePanelProps) {
  const [requests, setRequests] = useState<PatientRequest[]>([]);
  const [showRequests, setShowRequests] = useState(false);
  const [selectedRequest, setSelectedRequest] = useState<PatientRequest | null>(null);
  const [isOnline, setIsOnline] = useState(true);

  // Check if we are on localhost
  const isLocalhost = typeof window !== 'undefined' && window.location.hostname === 'localhost';

  // Generate the QR code URL ΓÇö points to the same app with ?intake=true
  const qrUrl = useMemo(() => {
    const base = typeof window !== 'undefined' ? window.location.origin + window.location.pathname : '';
    return `${base}?intake=true`;
  }, []);

  // Fetch initial requests from Supabase + subscribe to realtime updates
  useEffect(() => {
    let channel: ReturnType<typeof supabase.channel> | null = null;

    const fetchRequests = async () => {
      try {
        const { data, error } = await supabase
          .from('patient_requests')
          .select('*')
          .order('created_at', { ascending: false });

        if (error) throw error;

        const mapped = (data as PatientRequestRow[]).map(rowToPatientRequest);
        setRequests(mapped);
        setIsOnline(true);
      } catch (err) {
        console.error('Supabase fetch error, falling back to localStorage:', err);
        setIsOnline(false);
        // Fallback to localStorage
        const stored = JSON.parse(localStorage.getItem('smarter-patient-requests') || '[]') as PatientRequest[];
        setRequests(stored);
      }
    };

    fetchRequests();

    // Subscribe to realtime changes
    channel = supabase
      .channel('patient_requests_realtime')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'patient_requests' },
        (payload) => {
          if (payload.eventType === 'INSERT') {
            const newReq = rowToPatientRequest(payload.new as PatientRequestRow);
            setRequests(prev => [newReq, ...prev]);
          } else if (payload.eventType === 'UPDATE') {
            const updated = rowToPatientRequest(payload.new as PatientRequestRow);
            setRequests(prev => prev.map(r => r.id === updated.id ? updated : r));
          } else if (payload.eventType === 'DELETE') {
            const oldId = (payload.old as any).id;
            setRequests(prev => prev.filter(r => r.id !== oldId));
          }
        }
      )
      .subscribe();

    return () => {
      if (channel) supabase.removeChannel(channel);
    };
  }, []);

  // Fallback: poll localStorage when offline
  useEffect(() => {
    if (isOnline) return;
    const loadRequests = () => {
      const stored = JSON.parse(localStorage.getItem('smarter-patient-requests') || '[]') as PatientRequest[];
      setRequests(stored);
    };
    const interval = setInterval(loadRequests, 2000);
    return () => clearInterval(interval);
  }, [isOnline]);

  const clearRequests = async () => {
    if (isOnline) {
      try {
        await supabase.from('patient_requests').delete().neq('id', '');
      } catch (err) {
        console.error('Delete error:', err);
      }
    }
    localStorage.removeItem('smarter-patient-requests');
    setRequests([]);
    setSelectedRequest(null);
  };

  const updateRequestStatus = async (id: string, status: PatientRequest['status']) => {
    if (isOnline) {
      try {
        const { error } = await supabase
          .from('patient_requests')
          .update({ status })
          .eq('id', id);
        if (error) throw error;
      } catch (err) {
        console.error('Status update error:', err);
      }
    } else {
      // Fallback localStorage update
      const updated = requests.map(r => r.id === id ? { ...r, status } : r);
      localStorage.setItem('smarter-patient-requests', JSON.stringify(updated));
      setRequests(updated);
    }
    if (selectedRequest?.id === id) {
      setSelectedRequest({ ...selectedRequest, status });
    }
  };

  const pendingCount = requests.filter(r => r.status === 'Pending').length;

  const statusColors = {
    Pending: 'text-amber-400 bg-amber-500/10 border-amber-500/30',
    Reviewed: 'text-blue-400 bg-blue-500/10 border-blue-500/30',
    Admitted: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30',
  };

  const urgencyIcons = {
    Emergency: '≡ƒÜ¿',
    Urgent: 'ΓÜí',
    Standard: '≡ƒƒó',
  };

  return (
    <div className={`glass-card p-4 animate-fade-in-up ${className}`} style={{ animationDelay: '0.7s' }}>
      {/* Header */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <QrCode className="w-5 h-5 text-emerald-400" />
          <h3 className="text-sm font-semibold text-white">Patient Check-In</h3>
          {pendingCount > 0 && (
            <span className="relative flex h-5 w-5">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
              <span className="relative inline-flex items-center justify-center rounded-full h-5 w-5 bg-red-500 text-[10px] text-white font-bold">
                {pendingCount}
              </span>
            </span>
          )}
        </div>
        <div className="flex items-center gap-1.5">
          {/* Online/Offline indicator */}
          <div className={`flex items-center gap-1 px-1.5 py-0.5 rounded-md text-[9px] ${
            isOnline
              ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
              : 'bg-amber-500/10 text-amber-400 border border-amber-500/20'
          }`}>
            {isOnline ? <Cloud className="w-2.5 h-2.5" /> : <CloudOff className="w-2.5 h-2.5" />}
            {isOnline ? 'Live' : 'Local'}
          </div>
          {requests.length > 0 && (
            <>
              <button
                onClick={() => setShowRequests(!showRequests)}
                className="text-[10px] px-2 py-1 rounded-md bg-slate-800/50 border border-slate-700/30 text-slate-400 hover:text-white transition-colors"
              >
                {showRequests ? 'Hide' : 'View'} ({requests.length})
              </button>
              <button
                onClick={clearRequests}
                className="w-7 h-7 flex items-center justify-center rounded-md bg-slate-800/50 border border-slate-700/30 text-slate-500 hover:text-red-400 hover:border-red-500/30 transition-all"
                title="Clear all requests"
              >
                <Trash2 className="w-3 h-3" />
              </button>
            </>
          )}
        </div>
      </div>

      {isLocalhost && (
        <div className="mb-4 p-2 bg-amber-500/10 border border-amber-500/30 rounded-lg flex items-start gap-2 text-amber-400">
          <AlertCircle className="w-4 h-4 flex-shrink-0 mt-0.5" />
          <p className="text-[10px] leading-tight">
            You are viewing this on <strong>localhost</strong>. The QR code encodes "localhost", which won't work on your phone. <br/>
            Open this dashboard using your computer's network IP (e.g. <span className="font-mono text-white opacity-80">192.168.x.x:5174</span>) instead.
          </p>
        </div>
      )}

      {/* QR Code + Instructions */}
      <div className="flex flex-col sm:flex-row items-center gap-4">
        {/* QR Code */}
        <div className="bg-white rounded-xl p-3 shadow-lg shadow-emerald-500/10">
          <QRCodeSVG
            value={qrUrl}
            size={140}
            bgColor="#ffffff"
            fgColor="#0a0f1e"
            level="M"
            includeMargin={false}
          />
        </div>

        {/* Instructions */}
        <div className="flex-1 text-center sm:text-left">
          <p className="text-xs text-slate-300 mb-2 font-medium">
            Scan to self-register
          </p>
          <div className="space-y-1.5">
            <div className="flex items-center gap-2 text-[11px] text-slate-400">
              <span className="w-5 h-5 rounded-full bg-emerald-500/20 border border-emerald-500/30 flex items-center justify-center text-emerald-400 text-[9px] font-bold flex-shrink-0">1</span>
              Patient scans QR with phone camera
            </div>
            <div className="flex items-center gap-2 text-[11px] text-slate-400">
              <span className="w-5 h-5 rounded-full bg-emerald-500/20 border border-emerald-500/30 flex items-center justify-center text-emerald-400 text-[9px] font-bold flex-shrink-0">2</span>
              Fills in symptoms & medical history
            </div>
            <div className="flex items-center gap-2 text-[11px] text-slate-400">
              <span className="w-5 h-5 rounded-full bg-emerald-500/20 border border-emerald-500/30 flex items-center justify-center text-emerald-400 text-[9px] font-bold flex-shrink-0">3</span>
              Request appears here instantly via cloud
            </div>
          </div>
          <p className="text-[9px] text-slate-600 mt-2 break-all">
            {qrUrl}
          </p>
        </div>
      </div>

      {/* Patient Requests List */}
      {showRequests && requests.length > 0 && (
        <div className="mt-4 pt-3 border-t border-slate-700/30 space-y-2 max-h-[300px] overflow-y-auto">
          <div className="flex items-center gap-2 mb-2">
            {isOnline ? (
              <>
                <Cloud className="w-3 h-3 text-emerald-400" />
                <span className="text-[10px] text-emerald-400">Realtime ΓÇö updates instantly via Supabase</span>
              </>
            ) : (
              <>
                <RefreshCw className="w-3 h-3 text-slate-500 animate-spin" style={{ animationDuration: '3s' }} />
                <span className="text-[10px] text-slate-500">Local mode ΓÇö auto-refreshes every 2s</span>
              </>
            )}
          </div>

          {requests.map(req => (
            <div
              key={req.id}
              className={`p-3 rounded-xl bg-slate-800/40 border border-slate-700/30 hover:border-slate-600 transition-all cursor-pointer ${
                selectedRequest?.id === req.id ? 'ring-1 ring-emerald-500/40' : ''
              }`}
              onClick={() => setSelectedRequest(selectedRequest?.id === req.id ? null : req)}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2.5">
                  <span className="text-sm">{urgencyIcons[req.urgencyLevel]}</span>
                  <div>
                    <div className="text-xs font-medium text-white">{req.name}</div>
                    <div className="text-[10px] text-slate-500">
                      Age {req.age} ΓÇó Pain {req.painLevel}/10 ΓÇó {new Date(req.timestamp).toLocaleTimeString()}
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <span className={`text-[10px] px-2 py-0.5 rounded-full border ${statusColors[req.status]}`}>
                    {req.status}
                  </span>
                  <Eye className="w-3.5 h-3.5 text-slate-600" />
                </div>
              </div>

              {/* Expanded details */}
              {selectedRequest?.id === req.id && (
                <div className="mt-3 pt-3 border-t border-slate-700/20 space-y-2 animate-fade-in">
                  <div className="grid grid-cols-2 gap-2 text-[10px]">
                    <div>
                      <span className="text-slate-500 block">Symptoms</span>
                      <span className="text-slate-300">{req.symptoms}</span>
                    </div>
                    <div>
                      <span className="text-slate-500 block">Gender</span>
                      <span className="text-slate-300">{req.gender}</span>
                    </div>
                    <div>
                      <span className="text-slate-500 block">Phone</span>
                      <span className="text-slate-300">{req.phone || 'Not provided'}</span>
                    </div>
                    <div>
                      <span className="text-slate-500 block">Allergies</span>
                      <span className="text-slate-300">{req.allergies || 'None'}</span>
                    </div>
                    {req.existingConditions && (
                      <div className="col-span-2">
                        <span className="text-slate-500 block">Existing Conditions</span>
                        <span className="text-slate-300">{req.existingConditions}</span>
                      </div>
                    )}
                  </div>

                  {/* Action buttons */}
                  <div className="flex gap-2 pt-1">
                    {req.status === 'Pending' && (
                      <button
                        onClick={(e) => { e.stopPropagation(); updateRequestStatus(req.id, 'Reviewed'); }}
                        className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-blue-500/10 border border-blue-500/30 text-blue-400 text-[10px] font-medium hover:bg-blue-500/20 transition-all"
                      >
                        <Clock className="w-3 h-3" /> Mark Reviewed
                      </button>
                    )}
                    {(req.status === 'Pending' || req.status === 'Reviewed') && (
                      <button
                        onClick={(e) => { e.stopPropagation(); updateRequestStatus(req.id, 'Admitted'); }}
                        className="flex-1 flex items-center justify-center gap-1 py-1.5 rounded-lg bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 text-[10px] font-medium hover:bg-emerald-500/20 transition-all"
                      >
                        <CheckCircle2 className="w-3 h-3" /> Admit
                      </button>
                    )}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Empty state */}
      {showRequests && requests.length === 0 && (
        <div className="mt-4 pt-3 border-t border-slate-700/30 text-center py-4">
          <AlertCircle className="w-5 h-5 text-slate-600 mx-auto mb-2" />
          <p className="text-[10px] text-slate-500">No patient requests yet</p>
          <p className="text-[9px] text-slate-600">Scan the QR code to submit a test request</p>
        </div>
      )}
    </div>
  );
}

